import { z } from "zod";

/* ── Common field schemas (reusable) ──────── */

export const emailSchema = z
  .string()
  .min(1, "البريد الإلكتروني مطلوب")
  .email("البريد الإلكتروني غير صالح");

export const passwordSchema = z
  .string()
  .min(8, "كلمة المرور يجب أن تكون 8 أحرف على الأقل")
  .regex(/[A-Z]/, "يجب أن تحتوي على حرف كبير واحد على الأقل")
  .regex(/[a-z]/, "يجب أن تحتوي على حرف صغير واحد على الأقل")
  .regex(/[0-9]/, "يجب أن تحتوي على رقم واحد على الأقل");

export const nameSchema = z
  .string()
  .min(2, "الاسم يجب أن يكون حرفين على الأقل")
  .max(50, "الاسم يجب أن يكون 50 حرفاً كحد أقصى");

export const phoneSchema = z
  .string()
  .regex(
    /^(\+?966|0)?5\d{8}$/,
    "رقم الهاتف غير صالح — مثال: 05xxxxxxxx"
  )
  .optional()
  .or(z.literal(""));

/* ── Composite schemas ───────────────────── */

export const loginSchema = z.object({
  email: emailSchema,
  password: z.string().min(1, "كلمة المرور مطلوبة"),
});

export const registerSchema = z
  .object({
    name: nameSchema,
    email: emailSchema,
    password: passwordSchema,
    confirmPassword: z.string(),
  })
  .refine((data) => data.password === data.confirmPassword, {
    message: "كلمتا المرور غير متطابقتين",
    path: ["confirmPassword"],
  });

export type LoginInput = z.infer<typeof loginSchema>;
export type RegisterInput = z.infer<typeof registerSchema>;

export { cn } from "./cn";
export {
  formatBytes,
  formatDate,
  formatDateTime,
  formatNumber,
} from "./format";

/**
 * Generate a cryptographically secure random token.
 * Uses `crypto.getRandomValues` — works in both browser and Node.js.
 * @param length - Character length of the token (default 32)
 */
export function generateToken(length = 32): string {
  const chars =
    "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
  const array = new Uint8Array(length);
  crypto.getRandomValues(array);
  let result = "";
  for (let i = 0; i < length; i++) {
    result += chars[array[i]! % chars.length];
  }
  return result;
}

/**
 * Resolve a promise after a given delay.
 * Useful for simulating latency in dev or rate-limiting.
 */
export function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

